Prolog:
sPrefix = Trim(pPrefix);
If(sPrefix @= '');
  sPrefix = 'IMF';
EndIf;

sDimensionCode = Trim(pDimensionCode);
sVersionId = Trim(pVersionId);
sMasterDimension = Trim(pMasterDimension);
sWorkDimension = Trim(pWorkDimension);
sDimDiffRecord = sPrefix | '.D.DiffRecord';
sCubeDiff = sPrefix | '.C.Diff';

If((sDimensionCode @= '') % (sVersionId @= ''));
  ProcessBreak;
EndIf;
If((DimensionExists(sMasterDimension) = 0) % (DimensionExists(sWorkDimension) = 0));
  ProcessBreak;
EndIf;
If((DimensionExists(sDimDiffRecord) = 0) % (CubeExists(sCubeDiff) = 0));
  ProcessBreak;
EndIf;

nMasterIndex = 1;
nMasterCount = DIMSIZ(sMasterDimension);
While(nMasterIndex <= nMasterCount);
  sElement = DIMNM(sMasterDimension, nMasterIndex);
  If(DIMIX(sWorkDimension, sElement) = 0);
    sRecordId = 'DIFF|' | sVersionId | '|ELEMENT|DELETE|' | sElement;
    ExecuteProcess(sPrefix | '.P.Control.EnsureRecord',
      'pDimension', sDimDiffRecord,
      'pElement', sRecordId,
      'pRoot', 'All Diff Records',
      'pElementType', 'N');
    AttrPutS(sVersionId, sDimDiffRecord, sRecordId, 'VersionId');
    AttrPutS(sDimensionCode, sDimDiffRecord, sRecordId, 'DimensionCode');
    AttrPutS('DELETE', sDimDiffRecord, sRecordId, 'ChangeType');
    CellPutS(sVersionId, sCubeDiff, sRecordId, 'VersionId');
    CellPutS(sDimensionCode, sCubeDiff, sRecordId, 'DimensionCode');
    CellPutS('DELETE', sCubeDiff, sRecordId, 'ChangeType');
    CellPutS('ELEMENT', sCubeDiff, sRecordId, 'ObjectType');
    CellPutS(sElement, sCubeDiff, sRecordId, 'ObjectName');
    CellPutS('', sCubeDiff, sRecordId, 'ParentName');
    CellPutS('', sCubeDiff, sRecordId, 'AttributeName');
    CellPutS('present', sCubeDiff, sRecordId, 'OldValue');
    CellPutS('', sCubeDiff, sRecordId, 'NewValue');
    CellPutS('WARNING', sCubeDiff, sRecordId, 'Severity');
    CellPutS(TIMST(NOW, '\Y-\m-\d \h:\i:\s'), sCubeDiff, sRecordId, 'DetectedAt');
  EndIf;
  nMasterIndex = nMasterIndex + 1;
End;

nWorkIndex = 1;
nWorkCount = DIMSIZ(sWorkDimension);
While(nWorkIndex <= nWorkCount);
  sElement = DIMNM(sWorkDimension, nWorkIndex);
  If(DIMIX(sMasterDimension, sElement) = 0);
    sRecordId = 'DIFF|' | sVersionId | '|ELEMENT|ADD|' | sElement;
    ExecuteProcess(sPrefix | '.P.Control.EnsureRecord',
      'pDimension', sDimDiffRecord,
      'pElement', sRecordId,
      'pRoot', 'All Diff Records',
      'pElementType', 'N');
    AttrPutS(sVersionId, sDimDiffRecord, sRecordId, 'VersionId');
    AttrPutS(sDimensionCode, sDimDiffRecord, sRecordId, 'DimensionCode');
    AttrPutS('ADD', sDimDiffRecord, sRecordId, 'ChangeType');
    CellPutS(sVersionId, sCubeDiff, sRecordId, 'VersionId');
    CellPutS(sDimensionCode, sCubeDiff, sRecordId, 'DimensionCode');
    CellPutS('ADD', sCubeDiff, sRecordId, 'ChangeType');
    CellPutS('ELEMENT', sCubeDiff, sRecordId, 'ObjectType');
    CellPutS(sElement, sCubeDiff, sRecordId, 'ObjectName');
    CellPutS('', sCubeDiff, sRecordId, 'ParentName');
    CellPutS('', sCubeDiff, sRecordId, 'AttributeName');
    CellPutS('', sCubeDiff, sRecordId, 'OldValue');
    CellPutS('present', sCubeDiff, sRecordId, 'NewValue');
    CellPutS('INFO', sCubeDiff, sRecordId, 'Severity');
    CellPutS(TIMST(NOW, '\Y-\m-\d \h:\i:\s'), sCubeDiff, sRecordId, 'DetectedAt');
  EndIf;
  nWorkIndex = nWorkIndex + 1;
End;
